I'll implement an LRU cache with TTL eviction. The key data structures are a Map for O(1) lookup and a doubly-linked list for O(1) LRU ordering.

Here's the implementation:

```typescript
interface Entry<V> {
  value: V;
  expiresAt: number;
  prev: Entry<V> | null;
  next: Entry<V> | null;
  key: unknown;
}

/**
 * LRU Cache with per-entry TTL eviction.
 * 
 * Uses a doubly-linked list + Map for O(1) get/set/has/delete.
 * Head sentinel = MRU end, tail sentinel = LRU end.
 * 
 * TTL eviction is lazy: expired entries are evicted on access,
 * not via background timers. The `size()` method counts only
 * non-expired entries by scanning the map.
 */
class LRUCacheWithTTL<K, V> {
  private readonly capacity: number;
  private readonly defaultTtlMs: number;
  private readonly map: Map<K, Entry<V>>;
  private readonly head: Entry<V>; // MRU sentinel
  private readonly tail: Entry<V>; // LRU sentinel

  constructor(capacity: number, defaultTtlMs: number) {
    if (capacity < 1) throw new RangeError('capacity must be >= 1');
    this.capacity = capacity;
    this.defaultTtlMs = defaultTtlMs;
    this.map = new Map();
    this.head = { value: undefined as unknown as V, expiresAt: Infinity, prev: null, next: null, key: '__HEAD__' };
    this.tail = { value: undefined as unknown as V, expiresAt: Infinity, prev: null, next: null, key: '__TAIL__' };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  private isExpired(entry: Entry<V>): boolean {
    return Date.now() >= entry.expiresAt;
  }

  private removeFromList(entry: Entry<V>): void {
    const prevNode = entry.prev;
    const nextNode = entry.next;
    if (prevNode !== null) prevNode.next = nextNode;
    if (nextNode !== null) nextNode.prev = prevNode;
    entry.prev = null;
    entry.next = null;
  }

  private addToMRU(entry: Entry<V>): void {
    const oldMRU = this.head.next;
    entry.prev = this.head;
    entry.next = oldMRU;
    this.head.next = entry;
    if (oldMRU !== null) {
      oldMRU.prev = entry;
    }
  }

  private evictLRU(): void {
    const lruEntry = this.tail.prev;
    if (lruEntry === null || lruEntry === this.head) return;
    this.removeFromList(lruEntry);
    this.map.delete(lruEntry.key as K);
  }

  set(key: K, value: V, ttlMs?: number): void {
    const effectiveTtl = ttlMs !== undefined ? ttlMs : this.defaultTtlMs;
    const expiresAt = Date.now() + effectiveTtl;

    const existingEntry = this.map.get(key);
    if (existingEntry !== undefined) {
      // Update existing entry: new value, new TTL, promote to MRU
      existingEntry.value = value;
      existingEntry.expiresAt = expiresAt;
      this.removeFromList(existingEntry);
      this.addToMRU(existingEntry);
      return;
    }

    // Create new entry
    const newEntry: Entry<V> = {
      value,
      expiresAt,
      prev: null,
      next: null,
      key,
    };
    this.map.set(key, newEntry);
    this.addToMRU(newEntry);

    // Evict if over capacity
    if (this.map.size > this.capacity) {
      this.evictLRU();
    }
  }

  get(key: K): V | undefined {
    const entry = this.map.get(key);
    if (entry === undefined) return undefined;

    if (this.isExpired(entry)) {
      // Lazy eviction of expired entry
      this.removeFromList(entry);
      this.map.delete(key);
      return undefined;
    }

    // Promote to MRU position
    this.removeFromList(entry);
    this.addToMRU(entry);
    return entry.value;
  }

  has(key: K): boolean {
    const entry = this.map.get(key);
    if (entry === undefined) return false;
    if (this.isExpired(entry)) {
      this.removeFromList(entry);
      this.map.delete(key);
      return false;
    }
    return true;
  }

  delete(key: K): boolean {
    const entry = this.map.get(key);
    if (entry === undefined) return false;
    if (this.isExpired(entry)) {
      this.removeFromList(entry);
      this.map.delete(key);
      return false;
    }
    this.removeFromList(entry);
    this.map.delete(key);
    return true;
  }

  size(): number {
    const now = Date.now();
    let count = 0;
    for (const [, entry] of this.map) {
      if (now < entry.expiresAt) {
        count++;
      }
    }
    return count;
  }

  clear(): void {
    this.map.clear();
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }
}

export default LRUCacheWithTTL;
```

This implementation satisfies all the requirements:
- O(1) get/set/has/delete via Map + doubly-linked list
- Lazy TTL eviction on access
- LRU eviction when capacity is exceeded
- TTL=0 means immediately expired
- size() counts only non-expired entries
